use crate::solution::Solution;

#[test]
fn case_1() {
    let s = String::from(
        "abcabcbb"
    );

    let solution = Solution::length_of_longest_substring(
        s.clone()
    );

    assert_eq!(
        solution,
        3
    );
}

#[test]
fn case_2() {
    let s = String::from(
        "bbbbb"
    );

    let solution = Solution::length_of_longest_substring(
        s.clone()
    );

    assert_eq!(
        solution,
        1
    );
}

